        себе.боја = боја
        себе.тежина = тежина
        себе.разновидност = разновидност

    def get_color(self):
        врати се себе.боја

    def get_weight(self):
        враќање на себе.тежина

    def get_variety(self):
        врати се себе.разновидност

    def set_color (само, боја):
        себе.боја = боја

    def set_weight (само, тежина):
        себе.тежина = тежина

